const body = $json.body || $json;
const jobId = (body.job_id || '').trim();
if (!jobId) throw new Error('Must provide job_id in request body');
return [{ json: { jobId } }];

const pipelineRow = $('Read Pipeline Row').all()[0]?.json || {};
const evalRow = $('Read Evaluation Row').all()[0]?.json || {};

if (!pipelineRow.ID && !pipelineRow.id) {
  throw new Error('Job ID not found in Pipeline sheet. Run evaluation first.');
}

let evalData = {};
try { evalData = JSON.parse(evalRow['Full Report'] || '{}'); } catch(e) {}

return [{ json: {
  jobId: pipelineRow.ID || pipelineRow.id,
  company: pipelineRow.Company,
  title: pipelineRow.Title,
  url: pipelineRow.URL,
  grade: evalRow.Grade,
  overall: evalRow['Overall Score'],
  archetype: evalRow.Archetype,
  summary: evalRow['Executive Summary'],
  gaps: evalRow.Gaps,
  cvMatch: evalRow['CV Match'],
  evalData,
  keywords: (evalData.keywords || []).join(', ')
} }];

const sourceItem = $('Merge Job Context').first();
const htmlResponse = $input.first().json;
let jdText = '';

if (!htmlResponse.error && htmlResponse) {
  const html = typeof htmlResponse === 'string' ? htmlResponse : JSON.stringify(htmlResponse);
  jdText = html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&').replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ').trim().substring(0, 6000);
}

return [{ json: { ...sourceItem.json, jdText } }];
